package karn.platforms.leetcode.potd.date20260223;

import org.junit.jupiter.api.Test;

import java.io.File;
import java.io.FileNotFoundException;
import java.util.Scanner;

import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;


class SolutionTest {

    @Test
    void hasAllCodes() {
        Solution solution = new Solution();
        assertFalse(solution.hasAllCodes("", 20));
        assertFalse(solution.hasAllCodes("", 19));
    }

    @Test
    void hasAllCodeLargeInputFromFile() throws FileNotFoundException {
        Scanner sc = new Scanner(new File("src/main/resources/date23022026/tc1.txt"));
        String s = sc.nextLine();
        int k = sc.nextInt();
        sc.close();
        Solution solution = new Solution();
        assertTrue(solution.hasAllCodes(s, k));
    }
}